19	const (
20		defaultWorkerDirStaleAge          = 30 * time.Minute
21		executionRetentionArchiveRoot     = ".ddx/executions-archive"
22		executionRetentionOverrideEnv     = "DDX_EXECUTION_RETAIN_DAYS"
23		executionRetentionTimestampLayout = "20060102T150405"
