65	func newStartupHousekeepingRunner(projectRoot string) *startupHousekeepingRunner {
66		return &startupHousekeepingRunner{
67			projectRoot:     projectRoot,
68			tempRoot:        config.ExecutionTempRoot(projectRoot),
69			worktreeMaxAge:  worktreeReapMaxAgeFromEnv(),
70			workerDirMaxAge: defaultWorkerDirStaleAge,
71			retentionPolicy: resolveExecutionRetentionPolicy(projectRoot),
72		}
73	}
