75	func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
76		if r == nil {
77			return agent.ExecutionCleanupSummary{}, nil
78		}
79		report, err := r.scan(ctx, true)
80		if err != nil {
81			return agent.ExecutionCleanupSummary{
82				ProjectRoot: r.projectRoot,
83				TempRoot:    r.tempRoot,
84			}, err
85		}
86		return agent.ExecutionCleanupSummary{
87			ProjectRoot:                 report.ProjectRoot,
88			TempRoot:                    report.TempRoot,
89			RemovedRegisteredWorktrees:  report.RemovedRegisteredWorktrees,
90			RemovedUnregisteredTempDirs: report.RemovedUnregisteredTempDirs,
91			RemovedWorkerDirs:           report.RemovedWorkerDirs,
92			RemovedEvidenceDirs:         report.ArchivedExecutionDirs + report.DeletedExecutionDirs,
93			Warnings:                    append([]agent.ExecutionCleanupWarning(nil), report.Warnings...),
94		}, nil
95	}
