97	func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
98		if r == nil {
99			return startupHousekeepingReport{}, nil
100		}
101		report := startupHousekeepingReport{
102			ProjectRoot: r.projectRoot,
103			TempRoot:    r.tempRoot,
104		}
105		if r.projectRoot == "" {
106			return report, nil
107		}
108		now := time.Now().UTC()
109		if r.now != nil {
110			now = r.now()
111		}
112	
113		runStates, err := agent.ReadRunStates(r.projectRoot)
114		if err != nil {
115			return report, err
116		}
117		if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
118			return report, err
119		}
120		if err := r.scanWorkerDirs(ctx, now, apply, &report); err != nil {
121			return report, err
122		}
123		if err := r.scanExecutionDirs(ctx, now, runStates, apply, &report); err != nil {
124			return report, err
125		}
126		return report, nil
127	}
