129	func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
130		if report.TempRoot == "" {
131			return nil
132		}
133		if ctx != nil {
134			if err := ctx.Err(); err != nil {
135				return err
136			}
137		}
138		entries, err := os.ReadDir(report.TempRoot)
139		if err != nil {
140			if os.IsNotExist(err) {
141				return nil
142			}
143			return err
144		}
145	
146		registered := map[string]struct{}{}
147		if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
148			for _, path := range paths {
149				registered[filepath.Clean(path)] = struct{}{}
150			}
151		}
152	
153		for _, entry := range entries {
154			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
155				continue
156			}
157			if ctx != nil {
158				if err := ctx.Err(); err != nil {
159					return err
160				}
161			}
162			info, err := entry.Info()
163			if err != nil {
164				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
165					Path:    filepath.Join(report.TempRoot, entry.Name()),
166					Class:   "worktree_stat",
167					Message: err.Error(),
168				})
169				continue
170			}
171			if now.Sub(info.ModTime()) < r.worktreeMaxAge {
172				continue
173			}
174	
175			path := filepath.Join(report.TempRoot, entry.Name())
176			meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
177			if metaErr == nil {
178				meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
179			} else {
180				meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
181			}
182			if worktreeStillLive(meta, runStates, now) {
183				continue
184			}
185	
186			report.StaleWorktrees++
187			if !apply {
188				continue
189			}
190	
191			if _, ok := registered[filepath.Clean(path)]; ok {
192				if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
193					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
194						Path:    path,
195						Class:   "registered_worktree_remove",
196						Message: err.Error(),
197					})
198					continue
199				}
200				report.RemovedRegisteredWorktrees++
201				continue
202			}
203	
204			if err := os.RemoveAll(path); err != nil {
205				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
206					Path:    path,
207					Class:   "unregistered_worktree_remove",
208					Message: err.Error(),
209				})
210				continue
211			}
212			report.RemovedUnregisteredTempDirs++
213		}
214	
215		return nil
216	}
