171	// ExecutionCleanupLivenessProbe decides whether a cleanup candidate should be
172	// preserved because it is still live.
173	type ExecutionCleanupLivenessProbe interface {
174		IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string)
175	}
176	
177	// defaultExecutionCleanupLivenessProbe preserves preserved metadata, a temp
178	// execution directory referenced by the live run-state file, or a candidate
179	// with an unexpired liveness marker. Tests can override the probe to model
180	// more specific host behavior.
181	type defaultExecutionCleanupLivenessProbe struct{}
182	
183	func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
184		if meta.Preserved {
185			return true, "preserved metadata"
186		}
187		if meta.ActiveCandidateCycle {
188			return true, candidateCycleRecoveryReason(meta, "active candidate cycle")
189		}
190		if strings.TrimSpace(meta.CandidateRef) != "" {
191			return true, candidateCycleRecoveryReason(meta, "candidate ref recovery")
192		}
193		if runState != nil {
194			if strings.TrimSpace(runState.CandidateCyclePhase) != "" {
195				return true, candidateCycleRecoveryReason(candidateCycleMetadataFromRunState(*runState), "active candidate cycle")
196			}
197			if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
198				return true, "matched live run-state"
199			}
200			if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
201				return true, "matched live run-state"
202			}
203		}
204		if meta.Liveness != nil {
205			if meta.Liveness.PID > 0 && trackerProcessAlive(meta.Liveness.PID) {
206				return true, "live pid"
207			}
208			if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
209				return true, "unexpired liveness"
210			}
211			if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
212				return true, "fresh liveness"
213			}
214		}
215		return false, "stale liveness"
216	}
