218	// ExecutionCleanupManager owns conservative reclamation of DDx temp execution
219	// resources for one project.
220	type ExecutionCleanupManager struct {
221		ProjectRoot           string
222		TempRoot              string
223		ScratchRoots          []string
224		ScratchPrefixes       []string
225		ScratchMinAge         time.Duration
226		GitOps                GitOps
227		DryRun                bool
228		Now                   func() time.Time
229		Probe                 ExecutionCleanupLivenessProbe
230		attemptProcessScanner executionCleanupAttemptProcessScanner
231		attemptProcessKiller  executionCleanupAttemptProcessKiller
232		// RetainDays controls how many days of evidence dirs under
233		// .ddx/executions/ to retain. 0 disables the prune; default is 90.
234		RetainDays int
235	}
