237	// NewExecutionCleanupManager constructs a cleanup manager with the default
238	// DDx temp worktree root and the default liveness probe.
239	func NewExecutionCleanupManager(projectRoot string, gitOps GitOps) *ExecutionCleanupManager {
240		return &ExecutionCleanupManager{
241			ProjectRoot:           projectRoot,
242			TempRoot:              executionCleanupTempRoot(projectRoot),
243			RetainDays:            executionCleanupRetainDays(projectRoot),
244			GitOps:                gitOps,
245			Now:                   time.Now,
246			Probe:                 defaultExecutionCleanupLivenessProbe{},
247			attemptProcessScanner: newExecutionCleanupAttemptProcessScanner(),
248			attemptProcessKiller:  newExecutionCleanupAttemptProcessKiller(),
249		}
250	}
