252	// executionCleanupRetainDays returns the configured retain_days for evidence
253	// dirs, defaulting to defaultEvidenceRetainDays when not set in config.
254	func executionCleanupRetainDays(projectRoot string) int {
255		if projectRoot != "" {
256			projectConfig := ddxroot.JoinProject(projectRoot, "config.yaml")
257			cfg, err := config.LoadFromFile(projectConfig)
258			if err == nil && cfg != nil && cfg.Executions != nil {
259				return cfg.Executions.ResolveRetainDays()
260			}
261		}
262		return defaultEvidenceRetainDays
263	}
