265	// Cleanup scans the configured DDx temp worktree root, consults the project
266	// run-state file and git worktree registry, and conservatively removes stale
267	// DDx-owned temp resources.
268	func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
269		summary := ExecutionCleanupSummary{
270			ProjectRoot: m.ProjectRoot,
271			TempRoot:    m.tempRoot(),
272		}
273		if ctx != nil {
274			if err := ctx.Err(); err != nil {
275				return summary, err
276			}
277		}
278		if summary.TempRoot == "" {
279			summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
280		}
281		if summary.TempRoot == "" {
282			return summary, errors.New("execution cleanup: temp root is empty")
283		}
284		if m.ProjectRoot == "" {
285			return summary, errors.New("execution cleanup: project root is empty")
286		}
287		now := time.Now
288		if m.Now != nil {
289			now = m.Now
290		}
291		probe := m.Probe
292		if probe == nil {
293			probe = defaultExecutionCleanupLivenessProbe{}
294		}
295	
296		registered := map[string]struct{}{}
297		liveRunStates := map[string]struct{}{}
298		if m.GitOps != nil {
299			paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
300			if err != nil {
301				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
302					Path:    m.ProjectRoot,
303					Class:   "git_worktree_list",
304					Message: err.Error(),
305				})
306			} else {
307				for _, p := range paths {
308					registered[filepath.Clean(p)] = struct{}{}
309				}
310			}
311		}
312		if ctx != nil {
313			if err := ctx.Err(); err != nil {
314				return summary, err
315			}
316		}
317	
318		runStates, runStateErr := ReadRunStates(m.ProjectRoot)
319		if runStateErr != nil {
320			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
321				Path:    runStateDirPath(m.ProjectRoot),
322				Class:   "run_state_read",
323				Message: runStateErr.Error(),
324			})
325		}
326		if ctx != nil {
327			if err := ctx.Err(); err != nil {
328				return summary, err
329			}
330		}
331	
332		if len(runStates) > 0 || len(registered) > 0 {
333			if err := m.cleanupStaleAttemptProcessGroups(ctx, &summary, runStates, registered, probe, now()); err != nil {
334				return summary, err
335			}
336		}
337	
338		entries, err := os.ReadDir(summary.TempRoot)
339		if err != nil {
340			return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
341		}
342		for _, entry := range entries {
343			if !entry.IsDir() {
344				continue
345			}
346			if ctx != nil {
347				if err := ctx.Err(); err != nil {
348					return summary, err
349				}
350			}
351			if !hasAnyPrefix(entry.Name(), executionAttemptDirPrefixes()) {
352				continue
353			}
354			summary.ScannedTempDirs++
355			path := filepath.Join(summary.TempRoot, entry.Name())
356	
357			meta, metaErr := ReadExecutionCleanupMetadata(path)
358			missingMetadata := false
359			if metaErr != nil {
360				if errors.Is(metaErr, os.ErrNotExist) {
361					missingMetadata = true
362					meta = ExecutionCleanupMetadata{
363						ProjectRoot:  m.ProjectRoot,
364						WorktreePath: path,
365					}
366				} else {
367					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
368						Path:    path,
369						Class:   "metadata_read",
370						Message: metaErr.Error(),
371					})
372					continue
373				}
374			}
375			candidateRunStates := runStates
376			ownershipMismatch := meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot)
377			if ownershipMismatch {
378				candidateRunStates = m.runStatesForMetadata(meta, runStates, &summary)
379			}
380	
381			matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
382			live, reason := probe.IsLive(meta, matchedRunState, now())
383			if live {
384				if matchedRunState != nil {
385					liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
386				}
387				class := "preserved_temp_dir"
388				if isLiveAttemptPreservation(reason) {
389					class = "preserved_live_attempt"
390				}
391				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
392					Path:    path,
393					Class:   class,
394					Message: reason,
395				})
396				continue
397			}
398			if ownershipMismatch {
399				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
400					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
401						Path:    path,
402						Class:   "ownership_mismatch",
403						Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
404					})
405					continue
406				}
407				if m.isRegisteredWorktree(meta.ProjectRoot, path, &summary) {
408					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
409						Path:    path,
410						Class:   "preserved_foreign_registered_worktree",
411						Message: "foreign project worktree is still registered",
412					})
413					continue
414				}
415			}
416	
417			if _, ok := registered[filepath.Clean(path)]; ok {
418				if missingMetadata {
419					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
420						Path:    path,
421						Class:   "registered_missing_metadata",
422						Message: "registered DDx worktree has no cleanup metadata; preserving",
423					})
424					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
425						Path:    path,
426						Class:   "preserved_registered_missing_metadata",
427						Message: "registered worktree without cleanup metadata",
428					})
429					continue
430				}
431				if m.GitOps == nil {
432					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
433						Path:     path,
434						Class:    "registered_worktree",
435						Message:  "no git ops available to remove registered worktree",
436						Blocking: true,
437					})
438					continue
439				}
440				reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
441				if measureErr != nil {
442					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
443						Path:    path,
444						Class:   "measure_tree",
445						Message: measureErr.Error(),
446					})
447				}
448				if !m.DryRun {
449					if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
450						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
451							Path:     path,
452							Class:    "registered_worktree_remove",
453							Message:  err.Error(),
454							Blocking: true,
455						})
456						continue
457					}
458				}
459				summary.RemovedRegisteredWorktrees++
460				summary.BytesReclaimed += reclaimedBytes
461				summary.InodesReclaimed += reclaimedInodes
462				class := "removed_registered_worktree"
463				if m.DryRun {
464					class = "would_remove_registered_worktree"
465				}
466				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
467					Path:    path,
468					Class:   class,
469					Message: reason,
470					Bytes:   reclaimedBytes,
471					Inodes:  reclaimedInodes,
472				})
473				continue
474			}
475	
476			reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
477			if measureErr != nil {
478				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
479					Path:    path,
480					Class:   "measure_tree",
481					Message: measureErr.Error(),
482				})
483			}
484			if !m.DryRun {
485				if err := os.RemoveAll(path); err != nil {
486					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
487						Path:     path,
488						Class:    "unregistered_temp_dir_remove",
489						Message:  err.Error(),
490						Blocking: false,
491					})
492					continue
493				}
494			}
495			summary.RemovedUnregisteredTempDirs++
496			summary.BytesReclaimed += reclaimedBytes
497			summary.InodesReclaimed += reclaimedInodes
498			class := "removed_unregistered_temp_dir"
499			if m.DryRun {
500				class = "would_remove_unregistered_temp_dir"
501			}
502			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
503				Path:    path,
504				Class:   class,
505				Message: reason,
506				Bytes:   reclaimedBytes,
507				Inodes:  reclaimedInodes,
508			})
509		}
510	
511		if err := m.cleanupScratchRoots(ctx, &summary, runStates, registered, probe, now()); err != nil {
512			return summary, err
513		}
514	
515		if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
516			if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
517				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
518					Path:    m.ProjectRoot,
519					Class:   "worktree_prune",
520					Message: err.Error(),
521				})
522			}
523		}
524	
525		// Stale run-state files are removed when they point at an execution
526		// resource that is no longer live.
527		for _, state := range runStates {
528			if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
529				continue
530			}
531			if runStateWorktreeStillExists(state) {
532				continue
533			}
534			if removed, bytes := m.removeStaleRunState(state, &summary); removed {
535				summary.RemovedRunStateFiles++
536				summary.BytesReclaimed += bytes
537				summary.InodesReclaimed++
538			}
539		}
540	
541		if ctx != nil {
542			if err := ctx.Err(); err != nil {
543				return summary, err
544			}
545		}
546		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
547		m.pruneEvidenceDirs(ctx, &summary, runStates, now())
548		if ctx != nil {
549			if err := ctx.Err(); err != nil {
550				return summary, err
551			}
552		}
553		m.pruneAgentLogs(ctx, &summary, runStates, now())
554		if ctx != nil {
555			if err := ctx.Err(); err != nil {
556				return summary, err
557			}
558		}
559		m.pruneWorkerDirs(ctx, &summary, now())
560		if ctx != nil {
561			if err := ctx.Err(); err != nil {
562				return summary, err
563			}
564		}
565		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
566		m.cleanupDurableLandedCandidateRefs(&summary)
567	
568		return summary, nil
569	}
