571	func (m *ExecutionCleanupManager) cleanupScratchRoots(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, registered map[string]struct{}, probe ExecutionCleanupLivenessProbe, now time.Time) error {
572		prefixes := m.scratchPrefixes()
573		minAge := m.scratchMinAge()
574		tempRoot := filepath.Clean(summary.TempRoot)
575	
576		for _, root := range m.scratchRoots(summary.TempRoot) {
577			if ctx != nil {
578				if err := ctx.Err(); err != nil {
579					return err
580				}
581			}
582			entries, err := os.ReadDir(root)
583			if err != nil {
584				if !os.IsNotExist(err) {
585					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
586						Path:    root,
587						Class:   "scratch_root_read",
588						Message: err.Error(),
589					})
590				}
591				continue
592			}
593			for _, entry := range entries {
594				if !entry.IsDir() || !hasAnyPrefix(entry.Name(), prefixes) {
595					continue
596				}
597				if ctx != nil {
598					if err := ctx.Err(); err != nil {
599						return err
600					}
601				}
602				path := filepath.Join(root, entry.Name())
603				if sameCleanPath(path, tempRoot) || isPathWithin(path, tempRoot) {
604					continue
605				}
606				summary.ScannedScratchDirs++
607	
608				info, err := entry.Info()
609				if err != nil {
610					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
611						Path:    path,
612						Class:   "scratch_stat",
613						Message: err.Error(),
614					})
615					continue
616				}
617	
618				meta, metaErr := ReadExecutionCleanupMetadata(path)
619				if metaErr != nil {
620					if !errors.Is(metaErr, os.ErrNotExist) {
621						summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
622							Path:    path,
623							Class:   "scratch_metadata_read",
624							Message: metaErr.Error(),
625						})
626						continue
627					}
628					meta = ExecutionCleanupMetadata{
629						ProjectRoot:  m.ProjectRoot,
630						WorktreePath: path,
631					}
632				}
633				if meta.WorktreePath == "" {
634					meta.WorktreePath = path
635				}
636	
637				candidateRunStates := runStates
638				if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
639					if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
640						summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
641							Path:    path,
642							Class:   "scratch_ownership_mismatch",
643							Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
644						})
645						continue
646					}
647					candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
648					if m.isRegisteredWorktree(meta.ProjectRoot, path, summary) {
649						summary.PreservedActiveScratchDirs++
650						summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
651							Path:    path,
652							Class:   "preserved_active_scratch_dir",
653							Message: "foreign project worktree is still registered",
654						})
655						continue
656					}
657				}
658				if _, ok := registered[filepath.Clean(path)]; ok {
659					summary.PreservedActiveScratchDirs++
660					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
661						Path:    path,
662						Class:   "preserved_active_scratch_dir",
663						Message: "registered worktree",
664					})
665					continue
666				}
667	
668				matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
669				if live, reason := probe.IsLive(meta, matchedRunState, now); live {
670					summary.PreservedActiveScratchDirs++
671					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
672						Path:    path,
673						Class:   "preserved_active_scratch_dir",
674						Message: reason,
675					})
676					continue
677				}
678	
679				if age := now.Sub(info.ModTime()); age < minAge {
680					summary.PreservedActiveScratchDirs++
681					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
682						Path:    path,
683						Class:   "preserved_active_scratch_dir",
684						Message: fmt.Sprintf("fresh scratch dir age=%s min_age=%s", age.Round(time.Second), minAge),
685					})
686					continue
687				}
688	
689				reclaimedBytes, reclaimedInodes, measureErr := measureTreeWithContext(ctx, path)
690				if measureErr != nil {
691					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
692						Path:    path,
693						Class:   "scratch_measure_tree",
694						Message: measureErr.Error(),
695					})
696				}
697				if !m.DryRun {
698					if err := os.RemoveAll(path); err != nil {
699						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
700							Path:     path,
701							Class:    "scratch_dir_remove",
702							Message:  err.Error(),
703							Blocking: false,
704						})
705						continue
706					}
707				}
708				summary.RemovedScratchDirs++
709				summary.ScratchBytesReclaimed += reclaimedBytes
710				summary.ScratchInodesReclaimed += reclaimedInodes
711				summary.BytesReclaimed += reclaimedBytes
712				summary.InodesReclaimed += reclaimedInodes
713				class := "removed_scratch_dir"
714				if m.DryRun {
715					class = "would_remove_scratch_dir"
716				}
717				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
718					Path:    path,
719					Class:   class,
720					Message: "stale DDx scratch dir",
721					Bytes:   reclaimedBytes,
722					Inodes:  reclaimedInodes,
723				})
724			}
725		}
726		return nil
727	}
