729	func (m *ExecutionCleanupManager) runStatesForMetadata(meta ExecutionCleanupMetadata, fallback []RunState, summary *ExecutionCleanupSummary) []RunState {
730		if meta.ProjectRoot == "" || sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
731			return fallback
732		}
733		states, err := ReadRunStates(meta.ProjectRoot)
734		if err != nil {
735			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
736				Path:    runStateDirPath(meta.ProjectRoot),
737				Class:   "foreign_run_state_read",
738				Message: err.Error(),
739			})
740			return fallback
741		}
742		return states
743	}
744	
745	func (m *ExecutionCleanupManager) canReclaimForeignTestOwnedPath(projectRoot, path string) bool {
746		if projectRoot == "" || !isPathWithin(projectRoot, os.TempDir()) {
747			return false
748		}
749		cleanPath := filepath.Clean(path)
750		for _, root := range m.reclaimableTempRoots() {
751			if sameCleanPath(cleanPath, root) || isPathWithin(cleanPath, root) {
752				return true
753			}
754		}
755		return false
756	}
757	
758	func (m *ExecutionCleanupManager) isRegisteredWorktree(projectRoot, path string, summary *ExecutionCleanupSummary) bool {
759		if m.GitOps == nil || projectRoot == "" || path == "" {
760			return false
761		}
762		paths, err := m.GitOps.WorktreeList(projectRoot)
763		if err != nil {
764			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
765				Path:    projectRoot,
766				Class:   "foreign_git_worktree_list",
767				Message: err.Error(),
768			})
769			return false
770		}
771		clean := filepath.Clean(path)
772		for _, p := range paths {
773			if filepath.Clean(p) == clean {
774				return true
775			}
776		}
777		return false
778	}
779	
780	func (m *ExecutionCleanupManager) scratchRoots(tempRoot string) []string {
781		if len(m.ScratchRoots) > 0 {
782			return cleanUniquePaths(m.ScratchRoots)
783		}
784		var roots []string
785		if tempRoot != "" {
786			parent := filepath.Dir(filepath.Clean(tempRoot))
787			if parent != "" && parent != "." {
788				roots = append(roots, parent)
789			}
790		}
791		if m.ProjectRoot != "" {
792			roots = append(roots, config.ExecutionScratchRoot(m.ProjectRoot))
793		}
794		// Always include the legacy process temp dir so changing
795		// executions.temp_worktree_root does not strand older DDx-owned scratch.
796		roots = append(roots, os.TempDir())
797		return cleanUniquePaths(roots)
798	}
799	
800	func (m *ExecutionCleanupManager) reclaimableTempRoots() []string {
801		tempRoot := m.tempRoot()
802		roots := []string{tempRoot}
803		roots = append(roots, m.scratchRoots(tempRoot)...)
804		roots = append(roots, config.LegacyExecutionTempRoot(), os.TempDir())
805		return cleanUniquePaths(roots)
806	}
807	
808	func (m *ExecutionCleanupManager) scratchPrefixes() []string {
809		if len(m.ScratchPrefixes) > 0 {
810			return append([]string(nil), m.ScratchPrefixes...)
811		}
812		return append([]string(nil), defaultExecutionCleanupScratchPrefixes...)
813	}
814	
815	func (m *ExecutionCleanupManager) scratchMinAge() time.Duration {
816		if m.ScratchMinAge > 0 {
817			return m.ScratchMinAge
818		}
819		return defaultExecutionCleanupScratchMinAge
820	}
821	
822	func cleanUniquePaths(paths []string) []string {
823		seen := map[string]struct{}{}
824		var out []string
825		for _, p := range paths {
826			if p == "" {
827				continue
828			}
829			clean := filepath.Clean(p)
830			if _, ok := seen[clean]; ok {
831				continue
832			}
833			seen[clean] = struct{}{}
834			out = append(out, clean)
835		}
836		return out
837	}
838	
839	func hasAnyPrefix(name string, prefixes []string) bool {
840		for _, prefix := range prefixes {
841			if prefix != "" && strings.HasPrefix(name, prefix) {
842				return true
843			}
844		}
845		return false
846	}
