980		if info, statErr := os.Stat(path); statErr == nil {
981			present = true
982			bytes = info.Size()
983		} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
984			path = runStatePath(m.ProjectRoot)
985			if info, legacyErr := os.Stat(path); legacyErr == nil {
