1002		if !present {
1003			return false, 0
1004		}
1005		class := "removed_run_state"
1006		if m.DryRun {
1007			class = "would_remove_run_state"
1008		}
1009		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1010			Path:    path,
1011			Class:   class,
1012			Message: "stale run-state",
1013			Bytes:   bytes,
