1141	func measureTreeWithContext(ctx context.Context, path string) (bytes int64, inodes int64, err error) {
1142		if ctx != nil {
1143			if err := ctx.Err(); err != nil {
1144				return 0, 0, err
1145			}
1146		}
1147		info, err := os.Lstat(path)
1148		if err != nil {
1149			return 0, 0, err
1150		}
1151		if !info.IsDir() {
1152			return info.Size(), 1, nil
1153		}
1154		err = filepath.WalkDir(path, func(p string, d os.DirEntry, walkErr error) error {
1155			if ctx != nil {
1156				if err := ctx.Err(); err != nil {
1157					return err
1158				}
1159			}
1160			if walkErr != nil {
1161				return walkErr
1162			}
1163			inodes++
1164			fi, statErr := d.Info()
1165			if statErr != nil {
1166				return statErr
1167			}
1168			bytes += fi.Size()
1169			return nil
1170		})
1171		return bytes, inodes, err
1172	}
