1177	func (m *ExecutionCleanupManager) pruneEvidenceDirs(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
1178		if m.RetainDays == 0 {
1179			return
1180		}
1181		if ctx != nil && ctx.Err() != nil {
1182			return
1183		}
1184		cutoff := now.AddDate(0, 0, -m.RetainDays)
1185	
1186		activeAttempts := map[string]struct{}{}
1187		for _, rs := range runStates {
1188			if rs.AttemptID != "" {
1189				activeAttempts[rs.AttemptID] = struct{}{}
1190			}
1191		}
1192	
1193		root := executeBeadArtifactRoot(m.ProjectRoot)
1194		entries, err := os.ReadDir(root)
1195		if err != nil {
1196			if !errors.Is(err, os.ErrNotExist) {
1197				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1198					Path:    root,
1199					Class:   "evidence_dir_read",
1200					Message: err.Error(),
1201				})
1202			}
1203			return
1204		}
1205	
1206		for _, entry := range entries {
1207			if ctx != nil && ctx.Err() != nil {
1208				return
1209			}
1210			if !entry.IsDir() {
1211				continue
1212			}
1213			dirName := entry.Name()
1214			dirPath := filepath.Join(root, dirName)
1215			relPath := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, dirName))
1216	
1217			if _, ok := activeAttempts[dirName]; ok {
1218				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1219					Path:    relPath,
1220					Class:   "preserved_active_evidence_dir",
1221					Message: "active run-state reference",
1222				})
1223				continue
1224			}
1225	
1226			// Defensive: skip dirs with no result.json (may be in-flight).
1227			if _, statErr := os.Stat(filepath.Join(dirPath, "result.json")); statErr != nil {
1228				continue
1229			}
1230	
1231			info, infoErr := entry.Info()
1232			if infoErr != nil {
1233				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1234					Path:    dirPath,
1235					Class:   "evidence_dir_stat",
1236					Message: infoErr.Error(),
1237				})
1238				continue
1239			}
1240			if !info.ModTime().Before(cutoff) {
1241				continue
1242			}
1243	
1244			if !m.DryRun {
1245				m.removeEvidenceDir(ctx, dirPath, summary)
1246			}
1247			summary.RemovedEvidenceDirs++
1248			class := "removed_evidence_dir"
1249			if m.DryRun {
1250				class = "would_remove_evidence_dir"
1251			}
1252			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1253				Path:    relPath,
1254				Class:   class,
1255				Message: fmt.Sprintf("evidence dir older than %d days", m.RetainDays),
1256			})
1257		}
1258	}
