1260	// removeEvidenceDir stages tracked files for deletion via git rm, then
1261	// removes any remaining files with os.RemoveAll.
1262	func (m *ExecutionCleanupManager) removeEvidenceDir(ctx context.Context, dirPath string, summary *ExecutionCleanupSummary) {
1263		if m.ProjectRoot == "" {
