1266		}
1267		rel, err := filepath.Rel(m.ProjectRoot, dirPath)
1268		if err != nil || strings.HasPrefix(rel, "..") {
1269			_ = os.RemoveAll(dirPath)
1270			return
1271		}
1272		relSlash := filepath.ToSlash(rel)
1273	
1274		// Check for tracked files; if any, stage their deletion via git rm.
1275		lsOut, lsErr := internalgit.Command(ctx, m.ProjectRoot, "ls-files", relSlash).Output()
1276		if lsErr == nil && len(strings.TrimSpace(string(lsOut))) > 0 {
