1280					Path:    dirPath,
1281					Class:   "evidence_dir_git_rm",
1282					Message: fmt.Sprintf("git rm: %s: %v", strings.TrimSpace(string(rmOut)), rmErr),
1283				})
1284			}
1285		}
1286		// Remove remaining untracked files.
1287		_ = os.RemoveAll(dirPath)
