1447				})
1448				continue
1449			}
1450	
1451			info, infoErr := entry.Info()
1452			if infoErr != nil {
1453				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1454					Path:    dirPath,
1455					Class:   "worker_dir_stat",
1456					Message: infoErr.Error(),
1457				})
1458				continue
1459			}
1460			if !info.ModTime().Before(cutoff) {
1461				continue
1462			}
1463	
1464			if !m.DryRun {
1465				if err := os.RemoveAll(dirPath); err != nil {
1466					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1467						Path:    dirPath,
1468						Class:   "worker_dir_remove",
1469						Message: err.Error(),
1470					})
1471					continue
1472				}
1473			}
1474			summary.RemovedWorkerDirs++
1475			class := "removed_worker_dir"
1476			if m.DryRun {
1477				class = "would_remove_worker_dir"
1478			}
1479			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1480				Path:    relPath,
1481				Class:   class,
1482				Message: fmt.Sprintf("worker dir older than %d days", m.RetainDays),
1483			})
1484		}
1485	}
