1487	func scanCompleteEvidenceDirs(projectRoot, rootRel string, primaryFile, secondaryFile string, summary *ExecutionCleanupSummary) int {
1488		root := projectStatePath(projectRoot, rootRel)
1489		entries, err := os.ReadDir(root)
1490		if err != nil {
1491			return 0
1492		}
1493		count := 0
1494		for _, entry := range entries {
1495			if !entry.IsDir() {
1496				continue
1497			}
1498			count++
1499			full := filepath.Join(root, entry.Name())
1500			complete := false
1501			if primaryFile != "" {
1502				if _, err := os.Stat(filepath.Join(full, primaryFile)); err == nil {
1503					complete = true
1504				}
1505			}
1506			if !complete && secondaryFile != "" {
1507				if _, err := os.Stat(filepath.Join(full, secondaryFile)); err == nil {
1508					complete = true
1509				}
1510			}
1511			if complete {
1512				summary.CompleteEvidenceDirs++
1513				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1514					Path:    filepath.ToSlash(filepath.Join(rootRel, entry.Name())),
1515					Class:   "complete_evidence",
1516					Message: "complete evidence preserved",
1517				})
1518			}
1519		}
1520		return count
1521	}
