146	func (m *ExecutionCleanupManager) classifyExecutionCleanupAttemptProcessGroup(
147		group []executionCleanupAttemptProcess,
148		runStates []RunState,
149		registered map[string]struct{},
150		probe ExecutionCleanupLivenessProbe,
151		now time.Time,
152		summary *ExecutionCleanupSummary,
153	) (ExecutionCleanupProcessFinding, bool, error) {
154		if len(group) == 0 {
155			return ExecutionCleanupProcessFinding{}, false, nil
156		}
157		var staleProc *executionCleanupAttemptProcess
158		var staleMeta ExecutionCleanupMetadata
159		var staleReason string
160	
161		for i := range group {
162			proc := group[i]
163			if proc.PID <= 0 || proc.Worktree == "" {
164				continue
165			}
166			if !isPathWithin(proc.Worktree, m.tempRoot()) {
167				continue
168			}
169	
170			meta, err := ReadExecutionCleanupMetadata(proc.Worktree)
171			candidateRunStates := runStates
172			var matchedRunState *RunState
173	
174			switch {
175			case err == nil:
176				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
177					// Registered worktrees are active project state and are preserved
178					// even when the run-state file has already gone stale.
179					continue
180				}
181				if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
182					if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, proc.Worktree) {
183						continue
184					}
185					candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
186				}
187				matchedRunState = matchingRunStateForMeta(candidateRunStates, meta)
188			case errors.Is(err, os.ErrNotExist):
189				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
190					// Registered worktree without metadata stays conservative and
191					// does not get reaped from the process census alone.
192					continue
193				}
194				matchedRunState = matchingRunStateForMeta(runStates, ExecutionCleanupMetadata{WorktreePath: proc.Worktree})
195				if matchedRunState == nil {
196					continue
197				}
198				meta = candidateCycleMetadataFromRunState(*matchedRunState)
199				meta.ProjectRoot = m.ProjectRoot
200			default:
201				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
202					Path:    proc.Worktree,
203					Class:   "attempt_process_metadata_read",
204					Message: err.Error(),
205				})
206				continue
207			}
208	
209			live, reason := probe.IsLive(meta, matchedRunState, now)
210			if live {
211				return ExecutionCleanupProcessFinding{}, false, nil
212			}
213	
214			if staleProc == nil {
215				staleCopy := proc
216				staleProc = &staleCopy
217				staleMeta = meta
218				staleReason = reason
219			}
220		}
221	
222		if staleProc == nil {
223			return ExecutionCleanupProcessFinding{}, false, nil
224		}
225	
226		finding := ExecutionCleanupProcessFinding{
227			PID:         staleProc.PID,
228			PPID:        staleProc.PPID,
229			PGID:        staleProc.PGID,
230			BeadID:      staleMeta.BeadID,
231			AttemptID:   staleMeta.AttemptID,
232			Command:     staleProc.Command,
233			Cwd:         staleProc.Cwd,
234			Worktree:    staleProc.Worktree,
235			StartedAt:   staleProc.StartedAt,
236			StaleReason: staleReason,
237			WouldKill:   true,
238			Members:     make([]ExecutionCleanupProcessFact, 0, len(group)),
239		}
240		if finding.PGID <= 0 {
241			finding.PGID = finding.PID
242		}
243		for _, proc := range group {
244			finding.Members = append(finding.Members, ExecutionCleanupProcessFact(proc))
245		}
246		return finding, true, nil
247	}
248	
249	func groupExecutionCleanupAttemptProcesses(processes []executionCleanupAttemptProcess) []executionCleanupAttemptProcessGroup {
250		if len(processes) == 0 {
251			return nil
252		}
253		buckets := make(map[int][]executionCleanupAttemptProcess, len(processes))
254		for _, proc := range processes {
255			if proc.PID <= 0 || proc.PID == os.Getpid() {
256				continue
257			}
258			groupID := proc.PGID
259			if groupID <= 0 {
260				groupID = proc.PID
261			}
262			buckets[groupID] = append(buckets[groupID], proc)
263		}
264		if len(buckets) == 0 {
265			return nil
266		}
267	
268		groups := make([]executionCleanupAttemptProcessGroup, 0, len(buckets))
269		for groupID, members := range buckets {
270			sort.Slice(members, func(i, j int) bool {
271				if members[i].PID == members[j].PID {
272					return members[i].Command < members[j].Command
273				}
274				return members[i].PID < members[j].PID
275			})
276			groups = append(groups, executionCleanupAttemptProcessGroup{
277				GroupID: groupID,
278				Members: members,
279			})
280		}
281		sort.Slice(groups, func(i, j int) bool {
282			if groups[i].GroupID == groups[j].GroupID {
283				return pickExecutionCleanupAttemptRepresentative(groups[i].Members).PID < pickExecutionCleanupAttemptRepresentative(groups[j].Members).PID
284			}
285			return groups[i].GroupID < groups[j].GroupID
286		})
287		return groups
288	}
289	
290	func pickExecutionCleanupAttemptRepresentative(processes []executionCleanupAttemptProcess) executionCleanupAttemptProcess {
291		if len(processes) == 0 {
292			return executionCleanupAttemptProcess{}
293		}
294		for _, proc := range processes {
295			if proc.PID == proc.PGID && proc.PID > 0 {
296				return proc
297			}
298		}
299		return processes[0]
300	}
301	
302	func executionCleanupAttemptWorktreeRoot(path string) string {
303		path = strings.TrimSpace(path)
304		if path == "" {
305			return ""
306		}
307		path = strings.TrimSuffix(path, " (deleted)")
308		if !strings.Contains(path, ExecuteBeadWtPrefix) {
309			return ""
310		}
311		start := strings.Index(path, ExecuteBeadWtPrefix)
312		if start < 0 {
313			return ""
314		}
315		end := start + len(ExecuteBeadWtPrefix)
316		for end < len(path) {
317			switch path[end] {
318			case '/', '\\', ' ', '\t', '\x00':
319				return filepath.Clean(path[:end])
320			}
321			end++
322		}
323		return filepath.Clean(path)
324	}
