15	
16	type procExecutionCleanupAttemptProcessScanner struct {
17		now func() time.Time
18	}
19	
20	func newExecutionCleanupAttemptProcessScannerImpl() executionCleanupAttemptProcessScanner {
21		return &procExecutionCleanupAttemptProcessScanner{now: time.Now}
22	}
23	
24	func (s *procExecutionCleanupAttemptProcessScanner) Scan(ctx context.Context) ([]executionCleanupAttemptProcess, error) {
25		entries, err := os.ReadDir("/proc")
26		if err != nil {
27			return nil, fmt.Errorf("read /proc: %w", err)
28		}
29		bootTime := readExecutionCleanupBootTime("/proc/stat")
30		out := make([]executionCleanupAttemptProcess, 0)
31		for _, entry := range entries {
32			if ctx != nil && ctx.Err() != nil {
33				return nil, ctx.Err()
34			}
35			if !entry.IsDir() {
36				continue
37			}
38			pid, err := strconv.Atoi(entry.Name())
39			if err != nil || pid <= 0 {
40				continue
41			}
42			proc, ok := s.inspect(pid, bootTime)
43			if !ok {
44				continue
45			}
46			out = append(out, proc)
47		}
48		return out, nil
49	}
50	
51	func (s *procExecutionCleanupAttemptProcessScanner) inspect(pid int, bootTime time.Time) (executionCleanupAttemptProcess, bool) {
52		base := filepath.Join("/proc", strconv.Itoa(pid))
53		cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
54		if err != nil {
55			return executionCleanupAttemptProcess{}, false
56		}
57		cwd, _ := os.Readlink(filepath.Join(base, "cwd"))
58		ppid, pgid, startedAt, ok := readExecutionCleanupProcessStat(filepath.Join(base, "stat"), bootTime, s.now)
59		if !ok {
60			return executionCleanupAttemptProcess{}, false
61		}
62		cmdline := decodeExecutionCleanupCmdline(cmdlineRaw)
63		proc := executionCleanupAttemptProcessFromWorkerStatus(cmdline, cwd, pid, ppid, pgid, startedAt)
64		if proc.Worktree == "" {
65			return executionCleanupAttemptProcess{}, false
66		}
67		return proc, true
68	}
69	
70	func decodeExecutionCleanupCmdline(raw []byte) string {
71		if len(raw) == 0 {
72			return ""
73		}
74		if raw[len(raw)-1] == 0 {
75			raw = raw[:len(raw)-1]
76		}
77		parts := bytes.Split(raw, []byte{0})
78		out := make([]string, 0, len(parts))
79		for _, part := range parts {
80			if len(part) == 0 {
81				continue
82			}
83			out = append(out, string(part))
84		}
85		return strings.Join(out, " ")
