88	func readExecutionCleanupBootTime(statPath string) time.Time {
89		data, err := os.ReadFile(statPath)
90		if err != nil {
91			return time.Time{}
92		}
93		for _, line := range strings.Split(string(data), "\n") {
94			if !strings.HasPrefix(line, "btime ") {
95				continue
96			}
97			fields := strings.Fields(line)
98			if len(fields) < 2 {
99				continue
100			}
101			sec, err := strconv.ParseInt(fields[1], 10, 64)
102			if err != nil {
103				return time.Time{}
104			}
105			return time.Unix(sec, 0)
106		}
107		return time.Time{}
108	}
