110	func readExecutionCleanupProcessStat(statPath string, bootTime time.Time, now func() time.Time) (ppid int, pgid int, startedAt time.Time, ok bool) {
111		data, err := os.ReadFile(statPath)
112		if err != nil {
113			return 0, 0, time.Time{}, false
114		}
115		close := strings.LastIndex(string(data), ")")
116		if close < 0 {
117			return 0, 0, time.Time{}, false
118		}
119		tail := strings.Fields(string(data[close+1:]))
120		if len(tail) < 20 {
121			return 0, 0, time.Time{}, false
122		}
123		parsedPPID, err := strconv.Atoi(tail[1])
124		if err != nil {
125			return 0, 0, time.Time{}, false
126		}
127		parsedPGID, err := strconv.Atoi(tail[2])
128		if err != nil {
129			return 0, 0, time.Time{}, false
130		}
131		startClk, err := strconv.ParseInt(tail[19], 10, 64)
132		if err != nil {
133			return 0, 0, time.Time{}, false
134		}
135		if !bootTime.IsZero() {
136			seconds := float64(startClk) / 100.0
137			startedAt = bootTime.Add(time.Duration(seconds * float64(time.Second)))
138		}
139		if startedAt.IsZero() {
140			if now == nil {
141				now = time.Now
142			}
143			startedAt = now().UTC()
144		}
145		return parsedPPID, parsedPGID, startedAt.UTC(), true
146	}
