159	func jitteredCleanupDelay(base time.Duration, rng *rand.Rand) time.Duration {
160		if base <= 0 {
161			return 0
162		}
163		if rng == nil {
164			rng = rand.New(rand.NewSource(time.Now().UnixNano()))
165		}
166		if executionCleanupJitterFraction <= 0 {
167			return base
168		}
169		jitter := time.Duration(float64(base) * executionCleanupJitterFraction)
170		if jitter <= 0 {
171			return base
172		}
173		span := int64(jitter) * 2
174		if span <= 0 {
175			return base
176		}
177		offset := time.Duration(rng.Int63n(span+1)) - jitter
178		delay := base + offset
179		if delay < time.Second {
180			delay = time.Second
181		}
182		return delay
183	}
