185	func startExecutionCleanupWorker(ctx context.Context, projectRoot string, runner executionCleanupRunner, interval time.Duration, tickCh <-chan time.Time, log io.Writer, emit func(string, map[string]any)) (stop func(runShutdownPass bool)) {
186		if runner == nil {
187			return func(bool) {}
188		}
189		if interval <= 0 {
190			interval = defaultExecutionCleanupInterval
191		}
192	
193		workerCtx, cancel := context.WithCancel(ctx)
194		done := make(chan struct{})
195		go func() {
196			defer close(done)
197			var rng *rand.Rand
198			if tickCh == nil {
199				rng = rand.New(rand.NewSource(time.Now().UnixNano()))
200			}
201			for {
202				if tickCh != nil {
203					select {
204					case <-workerCtx.Done():
205						return
206					case <-tickCh:
207						_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
208					}
209					continue
210				}
211	
212				timer := time.NewTimer(jitteredCleanupDelay(interval, rng))
213				select {
214				case <-workerCtx.Done():
215					timer.Stop()
216					return
217				case <-timer.C:
218					_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
219				}
220			}
221		}()
222	
223		return func(runShutdownPass bool) {
224			cancel()
225			<-done
226			if runShutdownPass {
227				_, _, _ = runExecutionCleanupPass(context.Background(), projectRoot, runner, log, emit, "shutdown")
228			}
229		}
230	}
