244		for _, line := range lines {
245			fields := strings.Fields(string(line))
246			if len(fields) < 3 {
247				continue
248			}
249			pid, pidErr := strconv.Atoi(fields[0])
250			ppid, ppidErr := strconv.Atoi(fields[1])
251			pgid, pgidErr := strconv.Atoi(fields[2])
