func TestWorkStartupCleanup_UsesCleanupLockForProcessReaping(t *testing.T) {
    projectRoot := t.TempDir()
    testutils.MakeInitializedDDxRoot(t, projectRoot)

    var cleanupCalls int32
    var active int32
    var maxActive int32

    started := make(chan struct{})
    release := make(chan struct{})

    runner := cleanupRunnerFunc(func(ctx context.Context) (ExecutionCleanupSummary, error) {
        cur := atomic.AddInt32(&active, 1)
        for {
            prev := atomic.LoadInt32(&maxActive)
            if cur <= prev || atomic.CompareAndSwapInt32(&maxActive, prev, cur) {
                break
            }
        }
        atomic.AddInt32(&cleanupCalls, 1)
        select {
        case started <- struct{}{}:
        default:
        }
        select {
        case <-release:
        case <-ctx.Done():
        }
        atomic.AddInt32(&active, -1)
        return ExecutionCleanupSummary{}, nil
    })

    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()

    // First pass: starts and blocks.
    firstDone := make(chan struct{})
    go func() {
        defer close(firstDone)
        _, _, _ = runExecutionCleanupPass(ctx, projectRoot, runner, io.Discard, nil, "pre-claim")
    }()

    select {
    case <-started:
    case <-time.After(2 * time.Second):
        t.Fatal("first cleanup pass did not start")
    }
    assert.Equal(t, int32(1), atomic.LoadInt32(&cleanupCalls))

    // Second pass: must be skipped while the first holds the cleanup lock.
    _, skipped, err := runExecutionCleanupPass(ctx, projectRoot, runner, io.Discard, nil, "pre-claim")
    require.NoError(t, err)
    assert.True(t, skipped, "second cleanup pass must be skipped while cleanup lock is held")
    assert.Equal(t, int32(1), atomic.LoadInt32(&cleanupCalls),
        "process cleanup must not run twice concurrently — cleanup lock prevents race")
    assert.Equal(t, int32(1), atomic.LoadInt32(&maxActive),
        "cleanup passes must not overlap (process reaping protected by cleanup lock)")

    close(release)
    <-firstDone
}
