14	
15	const defaultExecutionCleanupInterval = 10 * time.Minute
16	const executionCleanupJitterFraction = 0.20
17	
18	const executionCleanupLockDirName = ".cleanup.lock"
19	
20	func executionCleanupLockPath(projectRoot string) string {
21		return ddxroot.JoinProject(projectRoot, executionCleanupLockDirName)
22	}
23	
24	// runExecutionCleanupPass conservatively runs the shared cleanup manager under
25	// a project-level lock. When another process already owns the lock, the pass
26	// is skipped and observed rather than blocking concurrent deletion.
27	func runExecutionCleanupPass(ctx context.Context, projectRoot string, runner executionCleanupRunner, log io.Writer, emit func(string, map[string]any), reason string) (ExecutionCleanupSummary, bool, error) {
28		if runner == nil {
29			return ExecutionCleanupSummary{}, false, nil
30		}
31		if projectRoot == "" {
32			return ExecutionCleanupSummary{}, false, fmt.Errorf("execution cleanup: project root is empty")
33		}
34	
35		release, acquired, err := tryAcquireExecutionCleanupLock(projectRoot)
36		if err != nil {
37			return ExecutionCleanupSummary{}, false, err
38		}
39		if !acquired {
40			if emit != nil {
41				emit("cleanup.skipped", map[string]any{
42					"project_root": projectRoot,
43					"reason":       reason,
44					"lock_path":    executionCleanupLockPath(projectRoot),
45				})
46			}
47			return ExecutionCleanupSummary{}, true, nil
48		}
49		defer release()
50	
51		summary, runErr := runner.Cleanup(ctx)
52		meaningful := executionCleanupSummaryMeaningful(summary)
53	
54		if emit != nil && meaningful {
55			emit("cleanup.pass", map[string]any{
56				"project_root":                summary.ProjectRoot,
57				"temp_root":                   summary.TempRoot,
58				"reason":                      reason,
59				"scanned_temp_dirs":           summary.ScannedTempDirs,
60				"scanned_evidence_dirs":       summary.ScannedEvidenceDirs,
61				"complete_evidence_dirs":      summary.CompleteEvidenceDirs,
62				"scanned_scratch_dirs":        summary.ScannedScratchDirs,
63				"removed_unregistered":        summary.RemovedUnregisteredTempDirs,
64				"removed_registered_worktree": summary.RemovedRegisteredWorktrees,
65				"removed_run_state":           summary.RemovedRunStateFiles,
66				"removed_scratch_dirs":        summary.RemovedScratchDirs,
67				"removed_evidence_dirs":       summary.RemovedEvidenceDirs,
68				"removed_agent_logs":          summary.RemovedAgentLogs,
69				"removed_worker_dirs":         summary.RemovedWorkerDirs,
70				"preserved_scratch_dirs":      summary.PreservedActiveScratchDirs,
71				"bytes_reclaimed":             summary.BytesReclaimed,
72				"inodes_reclaimed":            summary.InodesReclaimed,
73				"scratch_bytes_reclaimed":     summary.ScratchBytesReclaimed,
74				"scratch_inodes_reclaimed":    summary.ScratchInodesReclaimed,
75				"process_findings":            len(summary.ProcessFindings),
76				"warnings":                    len(summary.Warnings),
77				"issues":                      len(summary.Issues),
78			})
79		}
80		if meaningful && log != nil {
81			processFindings := len(summary.ProcessFindings)
82			fmt.Fprintf(log, "cleanup: %s %d temp dir(s), %d worktree(s), %d run-state file(s), %d scratch dir(s), %d evidence dir(s), %d agent log(s), %d worker dir(s), %d process group(s), %d byte(s), %d inode(s)\n",
83				reason,
84				summary.RemovedUnregisteredTempDirs,
85				summary.RemovedRegisteredWorktrees,
86				summary.RemovedRunStateFiles,
87				summary.RemovedScratchDirs,
88				summary.RemovedEvidenceDirs,
89				summary.RemovedAgentLogs,
90				summary.RemovedWorkerDirs,
91				processFindings,
92				summary.BytesReclaimed+summary.ScratchBytesReclaimed,
93				summary.InodesReclaimed+summary.ScratchInodesReclaimed,
94			)
95		}
96		return summary, false, runErr
97	}
98	
99	func executionCleanupSummaryMeaningful(summary ExecutionCleanupSummary) bool {
100		return len(summary.Issues) > 0 ||
101			len(summary.ProcessFindings) > 0 ||
102			summary.BytesReclaimed > 0 ||
103			summary.InodesReclaimed > 0 ||
104			summary.ScratchBytesReclaimed > 0 ||
105			summary.ScratchInodesReclaimed > 0 ||
106			summary.RemovedUnregisteredTempDirs > 0 ||
107			summary.RemovedRegisteredWorktrees > 0 ||
108			summary.RemovedRunStateFiles > 0 ||
109			summary.RemovedScratchDirs > 0 ||
110			summary.RemovedEvidenceDirs > 0 ||
111			summary.RemovedAgentLogs > 0 ||
112			summary.RemovedWorkerDirs > 0 ||
113			summary.PreservedActiveScratchDirs > 0
114	}
115	
116	func tryAcquireExecutionCleanupLock(projectRoot string) (func(), bool, error) {
117		lockDir := executionCleanupLockPath(projectRoot)
118		if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
119			return nil, false, fmt.Errorf("execution cleanup: lock dir: %w", err)
120		}
121		if err := os.Mkdir(lockDir, 0o755); err != nil {
122			if breakStaleExecutionCleanupLock(lockDir) {
123				if err := os.Mkdir(lockDir, 0o755); err != nil {
124					return nil, false, nil
125				}
126			} else {
127				return nil, false, nil
128			}
129		}
130		_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
131		_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
132		return func() { _ = os.RemoveAll(lockDir) }, true, nil
133	}
134	
135	func breakStaleExecutionCleanupLock(lockDir string) bool {
136		pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
137		if err == nil {
138			pid := 0
139			if _, scanErr := fmt.Sscanf(string(pidData), "%d", &pid); scanErr == nil && pid > 0 && pid != os.Getpid() {
140				if !trackerProcessAlive(pid) {
141					_ = os.RemoveAll(lockDir)
142					return true
143				}
144			}
145		}
146	
147		acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
148		if err == nil {
149			acquired, parseErr := time.Parse(time.RFC3339, string(acquiredData))
150			if parseErr == nil && time.Since(acquired) > trackerLockStaleAge {
151				_ = os.RemoveAll(lockDir)
152				return true
153			}
154		}
155	
156		return false
157	}
158	
159	func jitteredCleanupDelay(base time.Duration, rng *rand.Rand) time.Duration {
160		if base <= 0 {
161			return 0
162		}
163		if rng == nil {
164			rng = rand.New(rand.NewSource(time.Now().UnixNano()))
165		}
166		if executionCleanupJitterFraction <= 0 {
167			return base
168		}
169		jitter := time.Duration(float64(base) * executionCleanupJitterFraction)
170		if jitter <= 0 {
171			return base
172		}
173		span := int64(jitter) * 2
174		if span <= 0 {
175			return base
176		}
177		offset := time.Duration(rng.Int63n(span+1)) - jitter
178		delay := base + offset
179		if delay < time.Second {
180			delay = time.Second
181		}
182		return delay
183	}
184	
185	func startExecutionCleanupWorker(ctx context.Context, projectRoot string, runner executionCleanupRunner, interval time.Duration, tickCh <-chan time.Time, log io.Writer, emit func(string, map[string]any)) (stop func(runShutdownPass bool)) {
186		if runner == nil {
187			return func(bool) {}
188		}
189		if interval <= 0 {
190			interval = defaultExecutionCleanupInterval
191		}
192	
193		workerCtx, cancel := context.WithCancel(ctx)
194		done := make(chan struct{})
195		go func() {
196			defer close(done)
197			var rng *rand.Rand
198			if tickCh == nil {
199				rng = rand.New(rand.NewSource(time.Now().UnixNano()))
200			}
201			for {
202				if tickCh != nil {
203					select {
204					case <-workerCtx.Done():
205						return
206					case <-tickCh:
207						_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
208					}
209					continue
210				}
211	
212				timer := time.NewTimer(jitteredCleanupDelay(interval, rng))
213				select {
214				case <-workerCtx.Done():
215					timer.Stop()
216					return
217				case <-timer.C:
218					_, _, _ = runExecutionCleanupPass(workerCtx, projectRoot, runner, log, emit, "periodic")
219				}
220			}
221		}()
222	
223		return func(runShutdownPass bool) {
224			cancel()
225			<-done
226			if runShutdownPass {
227				_, _, _ = runExecutionCleanupPass(context.Background(), projectRoot, runner, log, emit, "shutdown")
228			}
229		}
230	}
