272	func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
273		policy := r.retentionPolicy
274		if policy.mode == executionRetentionDisabled {
275			return nil
276		}
277	
278		root := ddxroot.JoinProject(r.projectRoot, "executions")
279		entries, err := os.ReadDir(root)
280		if err != nil {
281			if os.IsNotExist(err) {
282				return nil
283			}
284			return err
285		}
286	
287		activeAttempts := map[string]struct{}{}
288		for _, rs := range runStates {
289			if rs.AttemptID != "" {
290				activeAttempts[rs.AttemptID] = struct{}{}
291			}
292		}
293		cutoff := now.AddDate(0, 0, -policy.days)
294	
295		for _, entry := range entries {
296			if !entry.IsDir() {
297				continue
298			}
299			if _, ok := activeAttempts[entry.Name()]; ok {
300				continue
301			}
302			if ctx != nil {
303				if err := ctx.Err(); err != nil {
304					return err
305				}
306			}
307	
308			dirPath := filepath.Join(root, entry.Name())
309			if !hasExecutionEvidenceMarker(dirPath) {
310				continue
311			}
312	
313			info, err := entry.Info()
314			if err != nil {
315				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
316					Path:    dirPath,
317					Class:   "execution_dir_stat",
318					Message: err.Error(),
319				})
320				continue
321			}
322			if !info.ModTime().Before(cutoff) {
323				continue
324			}
325	
326			report.StaleExecutionDirs++
327			if !apply {
328				continue
329			}
330	
331			switch policy.mode {
332			case executionRetentionArchive:
333				if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
334					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
335						Path:    dirPath,
336						Class:   "execution_dir_archive",
337						Message: err.Error(),
338					})
339					continue
340				}
341				report.ArchivedExecutionDirs++
342			case executionRetentionDelete:
343				if err := os.RemoveAll(dirPath); err != nil {
344					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
345						Path:    dirPath,
346						Class:   "execution_dir_remove",
347						Message: err.Error(),
348					})
349					continue
350				}
351				report.DeletedExecutionDirs++
352			}
353		}
354	
355		return nil
356	}
357	
358	func staleWorkerDir(rec workerstatus.LivenessRecord, now time.Time, maxAge time.Duration) (bool, string) {
359		if rec.PID > 0 && !processAlive(rec.PID) {
360			return true, fmt.Sprintf("worker pid %d is no longer live", rec.PID)
361		}
362		if !rec.LastActivityAt.IsZero() && now.Sub(rec.LastActivityAt) > maxAge {
363			return true, fmt.Sprintf("last activity older than %s", maxAge)
364		}
365		return false, ""
366	}
367	
368	func resolveExecutionRetentionPolicy(projectRoot string) executionRetentionPolicy {
369		if raw := strings.TrimSpace(os.Getenv(executionRetentionOverrideEnv)); raw != "" {
370			if days, err := strconv.Atoi(raw); err == nil && days >= 0 {
371				if days == 0 {
372					return executionRetentionPolicy{days: 0, mode: executionRetentionDelete}
373				}
374				return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
375			}
376		}
377	
378		cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
379		cfg, err := config.LoadFromFile(cfgPath)
380		if err != nil || cfg == nil || cfg.Executions == nil {
381			return executionRetentionPolicy{days: 90, mode: executionRetentionArchive}
382		}
383		days := cfg.Executions.ResolveRetainDays()
384		if days == 0 {
385			return executionRetentionPolicy{days: 0, mode: executionRetentionDisabled}
386		}
387		return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
388	}
389	
390	func hasExecutionEvidenceMarker(dirPath string) bool {
391		for _, name := range []string{"result.json", "manifest.json"} {
392			if _, err := os.Stat(filepath.Join(dirPath, name)); err == nil {
393				return true
394			}
395		}
396		return false
397	}
398	
399	func archiveExecutionDir(projectRoot, dirPath, attemptID string, modTime time.Time) error {
400		year, month := executionArchiveBucket(attemptID, modTime.UTC())
