func (r *startupHousekeepingRunner) scanAttemptProcesses(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
	if r == nil {
		return nil
	}
	if ctx != nil {
		if err := ctx.Err(); err != nil {
			return err
		}
	}
	registered := map[string]struct{}{}
	if paths, err := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); err == nil {
		for _, p := range paths {
			registered[filepath.Clean(p)] = struct{}{}
		}
	}
	findings, observations, warnings, err := agent.RunStartupAttemptProcessCleanup(
		ctx,
		r.projectRoot,
		r.tempRoot,
		runStates,
		registered,
		nil,
		r.processScanner,
		r.processKiller,
		!apply,
		now,
	)
	report.ProcessFindings = append(report.ProcessFindings, findings...)
	report.Observations = append(report.Observations, observations...)
	report.Warnings = append(report.Warnings, warnings...)
	return err
}

