func TestWorkStartupCleanup_ReapsStaleAttemptDescendantProcessesBeforeClaim(t *testing.T) {
	if runtime.GOOS != "linux" {
		t.Skip("attempt process cleanup scanner uses /proc; linux only")
	}

	projectRoot, tempRoot := setupWorkStartupCleanupProject(t)
	now := time.Date(2026, 6, 8, 12, 0, 0, 0, time.UTC)

	stalePath := filepath.Join(tempRoot, agent.ExecuteBeadWtPrefix+"ddx-stale-20260608T120000-deadbeef")
	require.NoError(t, os.MkdirAll(stalePath, 0o755))
	require.NoError(t, agent.WriteExecutionCleanupMetadata(stalePath, agent.ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       "ddx-stale",
		AttemptID:    "20260608T120000-deadbeef",
		WorktreePath: stalePath,
	}))
	// No run state → stale attempt with no live liveness markers.

	scanner := &fakeStartupScanner{facts: []agent.ExecutionCleanupProcessFact{
		{
			PID:      9001,
			PPID:     1,
			PGID:     9001,
			Command:  "sh -lc cargo test",
			Cwd:      stalePath,
			Worktree: stalePath,
		},
		{
			PID:      9002,
			PPID:     9001,
			PGID:     9001,
			Command:  "cargo test --workspace",
			Cwd:      filepath.Join(stalePath, "target"),
			Worktree: stalePath,
		},
	}}
	killer := &fakeStartupKiller{}

	runner := newStartupHousekeepingRunner(projectRoot)
	runner.tempRoot = tempRoot
	runner.processScanner = scanner
	runner.processKiller = killer
	runner.now = func() time.Time { return now }

	summary, err := runner.Cleanup(context.Background())
	require.NoError(t, err)

	assert.ElementsMatch(t, []int{9001}, killer.killed,
		"startup cleanup must reap stale attempt descendant process group before claim")
	require.Len(t, summary.ProcessFindings, 1)
	finding := summary.ProcessFindings[0]
	assert.Equal(t, 9001, finding.PID)
	assert.Equal(t, 9001, finding.PGID)
	assert.Equal(t, stalePath, finding.Worktree)
	assert.True(t, finding.Terminated, "process must be marked terminated")
	assert.NotEmpty(t, finding.StaleReason)
	assert.Len(t, finding.Members, 2)
}

func TestWorkStartupCleanup_PreservesUnsafeAttemptProcessesAndEmitsObservation(t *testing.T) {
	if runtime.GOOS != "linux" {
		t.Skip("attempt process cleanup scanner uses /proc; linux only")
	}

	projectRoot, tempRoot := setupWorkStartupCleanupProject(t)
	now := time.Date(2026, 6, 8, 13, 0, 0, 0, time.UTC)

	// Stale worktree: no run state, should be killed.
	stalePath := filepath.Join(tempRoot, agent.ExecuteBeadWtPrefix+"ddx-stale-20260608T130000-deadbeef")
	require.NoError(t, os.MkdirAll(stalePath, 0o755))
	require.NoError(t, agent.WriteExecutionCleanupMetadata(stalePath, agent.ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       "ddx-stale",
		AttemptID:    "20260608T130000-deadbeef",
		WorktreePath: stalePath,
	}))

	// Live worktree: has a matching run state, must be preserved.
	livePath := filepath.Join(tempRoot, agent.ExecuteBeadWtPrefix+"ddx-live-20260608T130000-feedface")
	require.NoError(t, os.MkdirAll(livePath, 0o755))
	require.NoError(t, agent.WriteExecutionCleanupMetadata(livePath, agent.ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       "ddx-live",
		AttemptID:    "20260608T130000-feedface",
		WorktreePath: livePath,
	}))
	require.NoError(t, agent.WriteRunState(projectRoot, agent.RunState{
		BeadID:       "ddx-live",
		AttemptID:    "20260608T130000-feedface",
		StartedAt:    now.Add(-5 * time.Minute),
		WorktreePath: livePath,
		PID:          os.Getpid(),
	}))

	// Registered worktree: must be preserved because it is an active git worktree.
	registeredPath := createRegisteredStartupWorktree(t, projectRoot, tempRoot, "ddx-registered", "20260608T130000-c001d00d")

	// Other-project process: outside tempRoot, must be ignored (not in scope).
	otherTempRoot := t.TempDir()
	otherPath := filepath.Join(otherTempRoot, agent.ExecuteBeadWtPrefix+"ddx-other-20260608T130000-abcd1234")
	require.NoError(t, os.MkdirAll(otherPath, 0o755))

	scanner := &fakeStartupScanner{facts: []agent.ExecutionCleanupProcessFact{
		// Stale: should be killed.
		{PID: 3001, PPID: 1, PGID: 3001, Command: "sh -lc cargo test", Cwd: stalePath, Worktree: stalePath},
		{PID: 3002, PPID: 3001, PGID: 3001, Command: "cargo test --workspace", Cwd: stalePath, Worktree: stalePath},
		// Live run-state: must be preserved with observation.
		{PID: 4001, PPID: 1, PGID: 4001, Command: "bash -lc sleep 60", Cwd: livePath, Worktree: livePath},
		// Registered worktree: must be preserved with observation.
		{PID: 5001, PPID: 1, PGID: 5001, Command: "python -m http.server 9999", Cwd: registeredPath, Worktree: registeredPath},
		// Other-project: outside tempRoot, silently skipped.
		{PID: 6001, PPID: 1, PGID: 6001, Command: "sh -lc sleep 60", Cwd: otherPath, Worktree: otherPath},
	}}
	killer := &fakeStartupKiller{}

	runner := newStartupHousekeepingRunner(projectRoot)
	runner.tempRoot = tempRoot
	runner.processScanner = scanner
	runner.processKiller = killer
	runner.now = func() time.Time { return now }

	summary, err := runner.Cleanup(context.Background())
	require.NoError(t, err)

	// Only the stale group must be killed.
	assert.ElementsMatch(t, []int{3001}, killer.killed,
		"only stale attempt process group must be killed")
	require.Len(t, summary.ProcessFindings, 1, "exactly one stale group in findings")
	assert.Equal(t, 3001, summary.ProcessFindings[0].PID)
	assert.True(t, summary.ProcessFindings[0].Terminated)

	// Live and registered processes must produce structured cleanup observations.
	var preservedObs []string
	for _, obs := range summary.Observations {
		if obs.Class == "preserved_attempt_process" {
			preservedObs = append(preservedObs, obs.Path)
		}
	}
	assert.Contains(t, preservedObs, livePath,
		"live run-state process must produce preserved_attempt_process observation")
	assert.Contains(t, preservedObs, registeredPath,
		"registered worktree process must produce preserved_attempt_process observation")
	// Other-project and outside-scope processes must not appear as findings or observations.
	for _, f := range summary.ProcessFindings {
		assert.NotEqual(t, 6001, f.PID, "other-project process must not appear in findings")
	}
}

