22	// ExecutionCleanupProcessFact) to the internal executionCleanupAttemptProcessScanner.
23	type startupScannerAdapter struct {
24		inner StartupAttemptProcessScanner
25	}
26	
27	func (a startupScannerAdapter) Scan(ctx context.Context) ([]executionCleanupAttemptProcess, error) {
28		facts, err := a.inner.Scan(ctx)
29		if err != nil {
30			return nil, err
31		}
32		out := make([]executionCleanupAttemptProcess, len(facts))
33		for i, f := range facts {
34			out[i] = executionCleanupAttemptProcess{
35				PID:       f.PID,
