47	// RunStartupAttemptProcessCleanup runs only the stale attempt process cleanup
48	// pass for work startup/pre-claim. It uses the same ownership and liveness
49	// rules as ExecutionCleanupManager.Cleanup: current-project execution root,
50	// stale or missing run-state liveness, dead owner PID, no live worker sidecar,
51	// no active registered worktree.
52	//
53	// Callers must hold the project cleanup lock (via runExecutionCleanupPass)
54	// before invoking this function to prevent multiple workers from racing to
55	// kill the same process group.
56	//
57	// scanner and killer may be nil; when nil, the platform defaults (real /proc
58	// scan and SIGKILL) are used. Set them in tests to inject controlled behaviour.
59	func RunStartupAttemptProcessCleanup(
60		ctx context.Context,
61		projectRoot, tempRoot string,
62		runStates []RunState,
63		registered map[string]struct{},
64		probe ExecutionCleanupLivenessProbe,
