149	func (m *ExecutionCleanupManager) classifyExecutionCleanupAttemptProcessGroup(
150		group []executionCleanupAttemptProcess,
151		runStates []RunState,
152		registered map[string]struct{},
153		probe ExecutionCleanupLivenessProbe,
154		now time.Time,
155		summary *ExecutionCleanupSummary,
156	) (ExecutionCleanupProcessFinding, bool, *ExecutionCleanupObservation, error) {
157		if len(group) == 0 {
158			return ExecutionCleanupProcessFinding{}, false, nil, nil
159		}
160		var staleProc *executionCleanupAttemptProcess
161		var staleMeta ExecutionCleanupMetadata
162		var staleReason string
163		var preservationObs *ExecutionCleanupObservation
164	
165		for i := range group {
166			proc := group[i]
167			if proc.PID <= 0 || proc.Worktree == "" {
168				continue
169			}
170			if !isPathWithin(proc.Worktree, m.tempRoot()) {
171				continue
172			}
173	
174			meta, err := ReadExecutionCleanupMetadata(proc.Worktree)
175			candidateRunStates := runStates
176			var matchedRunState *RunState
177	
178			switch {
179			case err == nil:
180				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
181					// Registered worktrees are active project state and are preserved
182					// even when the run-state file has already gone stale.
183					preservationObs = &ExecutionCleanupObservation{
184						Path:    proc.Worktree,
185						Class:   "preserved_attempt_process",
186						Message: "active registered worktree",
187					}
188					continue
189				}
190				if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
191					if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, proc.Worktree) {
192						continue
193					}
194					candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
195				}
196				matchedRunState = matchingRunStateForMeta(candidateRunStates, meta)
197			case errors.Is(err, os.ErrNotExist):
198				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
199					// Registered worktree without metadata stays conservative and
200					// does not get reaped from the process census alone.
201					preservationObs = &ExecutionCleanupObservation{
202						Path:    proc.Worktree,
203						Class:   "preserved_attempt_process",
204						Message: "active registered worktree",
205					}
206					continue
207				}
208				matchedRunState = matchingRunStateForMeta(runStates, ExecutionCleanupMetadata{WorktreePath: proc.Worktree})
209				if matchedRunState == nil {
210					continue
211				}
212				meta = candidateCycleMetadataFromRunState(*matchedRunState)
213				meta.ProjectRoot = m.ProjectRoot
214			default:
215				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
216					Path:    proc.Worktree,
217					Class:   "attempt_process_metadata_read",
218					Message: err.Error(),
219				})
220				continue
221			}
222	
223			live, reason := probe.IsLive(meta, matchedRunState, now)
224			if live {
225				return ExecutionCleanupProcessFinding{}, false, &ExecutionCleanupObservation{
226					Path:    proc.Worktree,
227					Class:   "preserved_attempt_process",
228					Message: reason,
229				}, nil
230			}
231	
232			if staleProc == nil {
233				staleCopy := proc
234				staleProc = &staleCopy
235				staleMeta = meta
236				staleReason = reason
237			}
238		}
239	
240		if staleProc == nil {
241			return ExecutionCleanupProcessFinding{}, false, preservationObs, nil
242		}
243	
244		finding := ExecutionCleanupProcessFinding{
245			PID:         staleProc.PID,
246			PPID:        staleProc.PPID,
247			PGID:        staleProc.PGID,
