249			AttemptID:   staleMeta.AttemptID,
250			Command:     staleProc.Command,
251			Cwd:         staleProc.Cwd,
252			Worktree:    staleProc.Worktree,
253			StartedAt:   staleProc.StartedAt,
254			StaleReason: staleReason,
255			WouldKill:   true,
256			Members:     make([]ExecutionCleanupProcessFact, 0, len(group)),
257		}
258		if finding.PGID <= 0 {
259			finding.PGID = finding.PID
260		}
261		for _, proc := range group {
262			finding.Members = append(finding.Members, ExecutionCleanupProcessFact(proc))
263		}
264		return finding, true, nil, nil
265	}
