267	func groupExecutionCleanupAttemptProcesses(processes []executionCleanupAttemptProcess) []executionCleanupAttemptProcessGroup {
268		if len(processes) == 0 {
269			return nil
270		}
271		buckets := make(map[int][]executionCleanupAttemptProcess, len(processes))
272		for _, proc := range processes {
273			if proc.PID <= 0 || proc.PID == os.Getpid() {
274				continue
275			}
276			groupID := proc.PGID
277			if groupID <= 0 {
278				groupID = proc.PID
279			}
280			buckets[groupID] = append(buckets[groupID], proc)
281		}
282		if len(buckets) == 0 {
283			return nil
284		}
285	
286		groups := make([]executionCleanupAttemptProcessGroup, 0, len(buckets))
287		for groupID, members := range buckets {
288			sort.Slice(members, func(i, j int) bool {
289				if members[i].PID == members[j].PID {
290					return members[i].Command < members[j].Command
291				}
292				return members[i].PID < members[j].PID
293			})
294			groups = append(groups, executionCleanupAttemptProcessGroup{
295				GroupID: groupID,
296				Members: members,
297			})
298		}
299		sort.Slice(groups, func(i, j int) bool {
300			if groups[i].GroupID == groups[j].GroupID {
301				return pickExecutionCleanupAttemptRepresentative(groups[i].Members).PID < pickExecutionCleanupAttemptRepresentative(groups[j].Members).PID
302			}
303			return groups[i].GroupID < groups[j].GroupID
304		})
305		return groups
306	}
307	
308	func pickExecutionCleanupAttemptRepresentative(processes []executionCleanupAttemptProcess) executionCleanupAttemptProcess {
309		if len(processes) == 0 {
310			return executionCleanupAttemptProcess{}
311		}
312		for _, proc := range processes {
313			if proc.PID == proc.PGID && proc.PID > 0 {
314				return proc
315			}
316		}
317		return processes[0]
318	}
319	
320	func executionCleanupAttemptWorktreeRoot(path string) string {
321		path = strings.TrimSpace(path)
322		if path == "" {
323			return ""
324		}
325		path = strings.TrimSuffix(path, " (deleted)")
326		if !strings.Contains(path, ExecuteBeadWtPrefix) {
327			return ""
328		}
329		start := strings.Index(path, ExecuteBeadWtPrefix)
330		if start < 0 {
331			return ""
332		}
333		end := start + len(ExecuteBeadWtPrefix)
334		for end < len(path) {
335			switch path[end] {
336			case '/', '\\', ' ', '\t', '\x00':
337				return filepath.Clean(path[:end])
338			}
339			end++
340		}
341		return filepath.Clean(path)
342	}
343	
344	func executionCleanupAttemptFactFromRaw(proc executionCleanupAttemptProcess) ExecutionCleanupProcessFact {
345		return ExecutionCleanupProcessFact(proc)
346	}
