348	func executionCleanupAttemptProcessFromWorkerStatus(cmdline, cwd string, pid, ppid, pgid int, startedAt time.Time) executionCleanupAttemptProcess {
349		_, worktree := workerstatus.InferBead(cmdline, cwd)
350		worktree = executionCleanupAttemptWorktreeRoot(worktree)
351		return executionCleanupAttemptProcess{
352			PID:       pid,
353			PPID:      ppid,
354			PGID:      pgid,
355			Command:   cmdline,
356			Cwd:       cwd,
357			Worktree:  worktree,
358			StartedAt: startedAt,
359		}
360	}
