171	func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
172		if report.TempRoot == "" {
173			return nil
174		}
175		if ctx != nil {
176			if err := ctx.Err(); err != nil {
177				return err
178			}
179		}
180		entries, err := os.ReadDir(report.TempRoot)
181		if err != nil {
182			if os.IsNotExist(err) {
183				return nil
184			}
185			return err
186		}
187	
188		registered := map[string]struct{}{}
189		if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
190			for _, path := range paths {
191				registered[filepath.Clean(path)] = struct{}{}
192			}
193		}
194	
195		for _, entry := range entries {
196			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
197				continue
198			}
199			if ctx != nil {
200				if err := ctx.Err(); err != nil {
201					return err
202				}
203			}
204			info, err := entry.Info()
205			if err != nil {
206				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
207					Path:    filepath.Join(report.TempRoot, entry.Name()),
208					Class:   "worktree_stat",
209					Message: err.Error(),
210				})
211				continue
212			}
213			if now.Sub(info.ModTime()) < r.worktreeMaxAge {
214				continue
215			}
216	
217			path := filepath.Join(report.TempRoot, entry.Name())
218			meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
219			if metaErr == nil {
220				meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
221			} else {
222				meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
223			}
224			if worktreeStillLive(meta, runStates, now) {
225				continue
226			}
227	
228			report.StaleWorktrees++
229			if !apply {
230				continue
231			}
232	
233			if _, ok := registered[filepath.Clean(path)]; ok {
234				if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
235					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
236						Path:    path,
237						Class:   "registered_worktree_remove",
238						Message: err.Error(),
239					})
240					continue
241				}
242				report.RemovedRegisteredWorktrees++
243				continue
244			}
245	
246			if err := os.RemoveAll(path); err != nil {
247				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
248					Path:    path,
249					Class:   "unregistered_worktree_remove",
250					Message: err.Error(),
251				})
252				continue
253			}
254			report.RemovedUnregisteredTempDirs++
255		}
256	
257		return nil
258	}
