260	func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
261		root := workerstatus.LivenessDir(r.projectRoot)
262		entries, err := os.ReadDir(root)
263		if err != nil {
264			if os.IsNotExist(err) {
265				return nil
266			}
267			return err
268		}
269	
270		for _, entry := range entries {
271			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
272				continue
273			}
274			if ctx != nil {
275				if err := ctx.Err(); err != nil {
276					return err
277				}
278			}
279	
280			rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
281			if err != nil {
282				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
283					Path:    filepath.Join(root, entry.Name(), "status.json"),
284					Class:   "worker_dir_read",
285					Message: err.Error(),
286				})
287				continue
288			}
289			stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
290			if !stale {
291				continue
292			}
293	
294			report.StaleWorkerDirs++
295			if !apply {
296				continue
297			}
298	
299			dirPath := filepath.Join(root, entry.Name())
300			if err := os.RemoveAll(dirPath); err != nil {
301				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
302					Path:    dirPath,
303					Class:   "worker_dir_remove",
304					Message: err.Error(),
305				})
306				continue
307			}
308			report.RemovedWorkerDirs++
309		}
310	
311		return nil
312	}
