314	func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
315		policy := r.retentionPolicy
316		if policy.mode == executionRetentionDisabled {
317			return nil
318		}
319	
320		root := ddxroot.JoinProject(r.projectRoot, "executions")
321		entries, err := os.ReadDir(root)
322		if err != nil {
323			if os.IsNotExist(err) {
324				return nil
325			}
326			return err
327		}
328	
329		activeAttempts := map[string]struct{}{}
330		for _, rs := range runStates {
331			if rs.AttemptID != "" {
332				activeAttempts[rs.AttemptID] = struct{}{}
333			}
334		}
335		cutoff := now.AddDate(0, 0, -policy.days)
336	
337		for _, entry := range entries {
338			if !entry.IsDir() {
339				continue
340			}
341			if _, ok := activeAttempts[entry.Name()]; ok {
342				continue
343			}
344			if ctx != nil {
345				if err := ctx.Err(); err != nil {
346					return err
347				}
348			}
349	
350			dirPath := filepath.Join(root, entry.Name())
351			if !hasExecutionEvidenceMarker(dirPath) {
352				continue
353			}
354	
355			info, err := entry.Info()
356			if err != nil {
357				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
358					Path:    dirPath,
359					Class:   "execution_dir_stat",
360					Message: err.Error(),
361				})
362				continue
363			}
364			if !info.ModTime().Before(cutoff) {
365				continue
366			}
367	
368			report.StaleExecutionDirs++
369			if !apply {
370				continue
371			}
372	
373			switch policy.mode {
374			case executionRetentionArchive:
375				if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
376					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
377						Path:    dirPath,
378						Class:   "execution_dir_archive",
379						Message: err.Error(),
380					})
381					continue
382				}
383				report.ArchivedExecutionDirs++
384			case executionRetentionDelete:
385				if err := os.RemoveAll(dirPath); err != nil {
386					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
387						Path:    dirPath,
388						Class:   "execution_dir_remove",
389						Message: err.Error(),
390					})
391					continue
392				}
393				report.DeletedExecutionDirs++
394			}
395		}
396	
397		return nil
398	}
399	
400	func staleWorkerDir(rec workerstatus.LivenessRecord, now time.Time, maxAge time.Duration) (bool, string) {
401		if rec.PID > 0 && !processAlive(rec.PID) {
402			return true, fmt.Sprintf("worker pid %d is no longer live", rec.PID)
403		}
404		if !rec.LastActivityAt.IsZero() && now.Sub(rec.LastActivityAt) > maxAge {
405			return true, fmt.Sprintf("last activity older than %s", maxAge)
406		}
407		return false, ""
408	}
409	
410	func resolveExecutionRetentionPolicy(projectRoot string) executionRetentionPolicy {
411		if raw := strings.TrimSpace(os.Getenv(executionRetentionOverrideEnv)); raw != "" {
412			if days, err := strconv.Atoi(raw); err == nil && days >= 0 {
413				if days == 0 {
414					return executionRetentionPolicy{days: 0, mode: executionRetentionDelete}
415				}
416				return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
417			}
418		}
419	
420		cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
421		cfg, err := config.LoadFromFile(cfgPath)
422		if err != nil || cfg == nil || cfg.Executions == nil {
423			return executionRetentionPolicy{days: 90, mode: executionRetentionArchive}
424		}
425		days := cfg.Executions.ResolveRetainDays()
426		if days == 0 {
427			return executionRetentionPolicy{days: 0, mode: executionRetentionDisabled}
428		}
429		return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
430	}
431	
432	func hasExecutionEvidenceMarker(dirPath string) bool {
433		for _, name := range []string{"result.json", "manifest.json"} {
434			if _, err := os.Stat(filepath.Join(dirPath, name)); err == nil {
435				return true
436			}
437		}
438		return false
439	}
440	
441	func archiveExecutionDir(projectRoot, dirPath, attemptID string, modTime time.Time) error {
442		year, month := executionArchiveBucket(attemptID, modTime.UTC())
443		dstRoot := filepath.Join(projectRoot, filepath.FromSlash(executionRetentionArchiveRoot), year, month)
444		if err := os.MkdirAll(dstRoot, 0o755); err != nil {
445			return fmt.Errorf("mkdir archive dir: %w", err)
446		}
447		dstPath := filepath.Join(dstRoot, attemptID)
448		if _, err := os.Stat(dstPath); err == nil {
449			return fmt.Errorf("archive destination already exists: %s", dstPath)
450		} else if !errors.Is(err, os.ErrNotExist) {
451			return err
452		}
453		return os.Rename(dirPath, dstPath)
454	}
455	
456	func executionArchiveBucket(attemptID string, modTime time.Time) (string, string) {
457		ts := attemptID
458		if idx := strings.IndexByte(ts, '-'); idx >= 0 {
459			ts = ts[:idx]
460		}
461		if parsed, err := time.ParseInLocation(executionRetentionTimestampLayout, ts, time.UTC); err == nil {
462			return parsed.Format("2006"), parsed.Format("01")
463		}
464		if modTime.IsZero() {
465			modTime = time.Now().UTC()
466		}
467		return modTime.Format("2006"), modTime.Format("01")
468	}
