package agent

import (
	"context"
	"time"
)

// StartupAttemptProcessScanner is an injectable census interface for DDx-owned
// attempt-descendant processes. Tests implement this to provide controlled
// process lists without scanning the live process table.
type StartupAttemptProcessScanner interface {
	Scan(context.Context) ([]ExecutionCleanupProcessFact, error)
}

// StartupAttemptProcessKiller terminates a DDx-owned attempt process group by
// PGID. Tests implement this to record kill requests without sending signals.
type StartupAttemptProcessKiller interface {
	KillGroup(int) error
}

// startupScannerAdapter adapts StartupAttemptProcessScanner (uses exported
// ExecutionCleanupProcessFact) to the internal executionCleanupAttemptProcessScanner.
type startupScannerAdapter struct {
	inner StartupAttemptProcessScanner
}

func (a startupScannerAdapter) Scan(ctx context.Context) ([]executionCleanupAttemptProcess, error) {
	facts, err := a.inner.Scan(ctx)
	if err != nil {
		return nil, err
	}
	out := make([]executionCleanupAttemptProcess, len(facts))
	for i, f := range facts {
		out[i] = executionCleanupAttemptProcess{
			PID:       f.PID,
			PPID:      f.PPID,
			PGID:      f.PGID,
			Command:   f.Command,
			Cwd:       f.Cwd,
			Worktree:  f.Worktree,
			StartedAt: f.StartedAt,
		}
	}
	return out, nil
}

// RunStartupAttemptProcessCleanup runs only the stale attempt process cleanup
// pass for work startup/pre-claim. It uses the same ownership and liveness
// rules as ExecutionCleanupManager.Cleanup: current-project execution root,
// stale or missing run-state liveness, dead owner PID, no live worker sidecar,
// no active registered worktree.
//
// Callers must hold the project cleanup lock (via runExecutionCleanupPass)
// before invoking this function to prevent multiple workers from racing to
// kill the same process group.
//
// scanner and killer may be nil; when nil, the platform defaults (real /proc
// scan and SIGKILL) are used. Set them in tests to inject controlled behaviour.
func RunStartupAttemptProcessCleanup(
	ctx context.Context,
	projectRoot, tempRoot string,
	runStates []RunState,
	registered map[string]struct{},
	probe ExecutionCleanupLivenessProbe,
	scanner StartupAttemptProcessScanner,
	killer StartupAttemptProcessKiller,
	dryRun bool,
	now time.Time,
) (findings []ExecutionCleanupProcessFinding, observations []ExecutionCleanupObservation, warnings []ExecutionCleanupWarning, err error) {
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}
	mgr := &ExecutionCleanupManager{
		ProjectRoot: projectRoot,
		TempRoot:    tempRoot,
		DryRun:      dryRun,
		Now:         func() time.Time { return now },
		Probe:       probe,
		GitOps:      &RealGitOps{},
	}
	if scanner != nil {
		mgr.attemptProcessScanner = startupScannerAdapter{inner: scanner}
	} else {
		mgr.attemptProcessScanner = newExecutionCleanupAttemptProcessScanner()
	}
	if killer != nil {
		mgr.attemptProcessKiller = killer
	} else {
		mgr.attemptProcessKiller = newExecutionCleanupAttemptProcessKiller()
	}

	summary := ExecutionCleanupSummary{}
	if err := mgr.cleanupStaleAttemptProcessGroups(ctx, &summary, runStates, registered, probe, now); err != nil {
		return nil, nil, nil, err
	}
	return summary.ProcessFindings, summary.Observations, summary.Warnings, nil
}

package agent

import (
	"context"
	"io"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/testutils"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestWorkStartupCleanup_UsesCleanupLockForProcessReaping(t *testing.T) {
	projectRoot := t.TempDir()
	testutils.MakeInitializedDDxRoot(t, projectRoot)

	var cleanupCalls int32
	var active int32
	var maxActive int32

	started := make(chan struct{})
	release := make(chan struct{})

	runner := cleanupRunnerFunc(func(ctx context.Context) (ExecutionCleanupSummary, error) {
		cur := atomic.AddInt32(&active, 1)
		for {
			prev := atomic.LoadInt32(&maxActive)
			if cur <= prev || atomic.CompareAndSwapInt32(&maxActive, prev, cur) {
				break
			}
		}
		atomic.AddInt32(&cleanupCalls, 1)
		select {
		case started <- struct{}{}:
		default:
		}
		select {
		case <-release:
		case <-ctx.Done():
		}
		atomic.AddInt32(&active, -1)
		return ExecutionCleanupSummary{}, nil
	})

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// First pass: starts and blocks.
	firstDone := make(chan struct{})
	go func() {
		defer close(firstDone)
		_, _, _ = runExecutionCleanupPass(ctx, projectRoot, runner, io.Discard, nil, "pre-claim")
	}()

	select {
	case <-started:
	case <-time.After(2 * time.Second):
		t.Fatal("first cleanup pass did not start")
	}
	assert.Equal(t, int32(1), atomic.LoadInt32(&cleanupCalls))

	// Second pass: must be skipped while the first holds the cleanup lock.
	_, skipped, err := runExecutionCleanupPass(ctx, projectRoot, runner, io.Discard, nil, "pre-claim")
	require.NoError(t, err)
	assert.True(t, skipped, "second cleanup pass must be skipped while cleanup lock is held")
	assert.Equal(t, int32(1), atomic.LoadInt32(&cleanupCalls),
		"process cleanup must not run twice concurrently — cleanup lock prevents race")
	assert.Equal(t, int32(1), atomic.LoadInt32(&maxActive),
		"cleanup passes must not overlap (process reaping protected by cleanup lock)")

	close(release)
	<-firstDone
}

